package main

import (
	"log"
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	// Custom metrics for user and request tracking
	userRequests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total number of requests per user",
		},
		[]string{"user_id", "endpoint", "status"},
	)

	userResponseTime = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "user_response_time_seconds",
			Help:    "Response time in seconds per user",
			Buckets: prometheus.ExponentialBuckets(0.001, 2, 20),
		},
		[]string{"user_id", "endpoint", "status"},
	)

	requestsInFlight = prometheus.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "requests_in_flight",
			Help: "Number of requests currently being processed per user",
		},
		[]string{"user_id", "endpoint"},
	)

	// Global metrics
	totalRequests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "total_requests_processed",
			Help: "Total number of requests processed",
		},
		[]string{"method", "endpoint", "status"},
	)

	totalResponseTime = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "total_response_time_seconds",
			Help:    "Total response time in seconds",
			Buckets: prometheus.ExponentialBuckets(0.001, 2, 20),
		},
		[]string{"method", "endpoint", "status"},
	)
)

func init() {
	prometheus.MustRegister(userRequests)
	prometheus.MustRegister(userResponseTime)
	prometheus.MustRegister(requestsInFlight)
	prometheus.MustRegister(totalRequests)
	prometheus.MustRegister(totalResponseTime)
}

func trackUserRequest(userID, endpoint, method, status string, duration time.Duration) {
	userRequests.WithLabelValues(userID, endpoint, status).Inc()
	userResponseTime.WithLabelValues(userID, endpoint, status).Observe(duration.Seconds())
	totalRequests.WithLabelValues(method, endpoint, status).Inc()
	totalResponseTime.WithLabelValues(method, endpoint, status).Observe(duration.Seconds())
}

func main() {
	http.HandleFunc("/user/{user_id}/endpoint/{endpoint}", func(w http.ResponseWriter, r *http.Request) {
		// Extract user ID and endpoint from URL
		userID := r.URL.Path[strings.LastIndex(r.URL.Path, "/")+1:]
		endpoint := r.URL.Path[strings.LastIndex(r.URL.Path, "/endpoint/")+9:]
		
		// Simulate request processing
		start := time.Now()
		
		// Increment in-flight requests
		requestsInFlight.WithLabelValues(userID, endpoint).Inc()
		
		// Simulate some work
		time.Sleep(100 * time.Millisecond)
		
		// Decrement in-flight requests
		requestsInFlight.WithLabelValues(userID, endpoint).Dec()
		
		// Record metrics
		duration := time.Since(start)
		status := "200"
		if r.URL.Path == "/error" {
			status = "500"
		}
		
		trackUserRequest(userID, endpoint, r.Method, status, duration)
		
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("Success"))
	})

	http.Handle("/metrics", promhttp.Handler())
	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}